// // This module compares two 16-bit inputs, a and b, and outputs the smaller of the two as 'out'. It also provides a selection mechanism: when 'sel' is 0, the output is the smaller value; when 'sel' is 1, the output is a third 16-bit input, 'c'. Additionally, the module outputs a signal 'not_equal' that indicates whether the two inputs, 'a' and 'b', are not equal.
module top_module(
    input [15:0] a,
    input [15:0] b,
    input [15:0] c,
    input sel,
    output [15:0] out,
    output equal
);wire [15:0] larger;
    assign larger = (a > b) ? a : b;

    assign out = (sel == 1'b0) ? larger : c;

    assign equal = (a == b) ? 1'b1 : 1'b0;

endmodule
